                rs.getString("url"),
                rs.getLong("size_bytes"),
                rs.getString("mime_type"),
                rs.getInt("width"),
                rs.getInt("height"),
                rs.getString("metadata"),
                rs.getTimestamp("created_at")?.toLocalDateTime()
            ) else null
        }
    }

